class TestHistoricalVersionPreservation:
    """Verify that every update persists a historical snapshot."""

    def test_history_saved_once_per_update(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        history_repo.save.assert_called_once()

    def test_history_snapshot_captures_pre_update_values(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        saved_hist: DemographicsHistory = history_repo.save.call_args[0][0]
        assert saved_hist.snapshot.phone == "555-1234"  # original value

    def test_history_snapshot_preserves_original_version(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        saved_hist: DemographicsHistory = history_repo.save.call_args[0][0]
        assert saved_hist.version == 1  # version BEFORE the update

    def test_history_recorded_by_matches_clinician(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        saved_hist: DemographicsHistory = history_repo.save.call_args[0][0]
        assert saved_hist.recorded_by == "DR-42"

    def test_history_patient_id_matches(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        saved_hist: DemographicsHistory = history_repo.save.call_args[0][0]
        assert saved_hist.patient_id == "P-001"

    def test_history_has_unique_history_id(self, service, history_repo):
        service.update_demographics("DR-42", "P-001", {"phone": "111"})
        service.update_demographics("DR-42", "P-001", {"phone": "222"})
        calls = history_repo.save.call_args_list
        id_1 = calls[0][0][0].history_id
        id_2 = calls[1][0][0].history_id
        assert id_1 != id_2

    def test_multiple_updates_produce_multiple_history_entries(
        self, service, history_repo
    ):
        service.update_demographics("DR-42", "P-001", {"phone": "111"})
        service.update_demographics("DR-42", "P-001", {"phone": "222"})
        assert history_repo.save.call_count == 2

    def test_history_saved_before_patient_saved(self, service, history_repo, patient_repo):
        """History must be written BEFORE the authoritative record is mutated."""
        call_order = []
        history_repo.save.side_effect = lambda _: call_order.append("history")
        patient_repo.save.side_effect = lambda _: call_order.append("patient")

        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        assert call_order == ["history", "patient"]

    def test_history_recorded_at_matches_clock(self, service, history_repo, fixed_now):
        service.update_demographics("DR-42", "P-001", {"phone": "555-9999"})
        saved_hist: DemographicsHistory = history_repo.save.call_args[0][0]
        assert saved_hist.recorded_at == fixed_now

    def test_get_history_returns_all_versions(self, service, history_repo):
        fake_histories = [MagicMock(), MagicMock(), MagicMock()]
        history_repo.get_all.return_value = fake_histories
        result = service.get_history("P-001")
        assert result == fake_histories
        history_repo.get_all.assert_called_once_with("P-001")


class TestTimestampBoundaryCases:
    """Boundary conditions on date_of_birth and updated_at timestamps."""

    def test_dob_exactly_today_raises_error(self, service):
        today = datetime.utcnow().strftime("%Y-%m-%d")
        # A patient born exactly 'today' is on the boundary – still valid clinically,
        # but services may differ; here we mark future dates as invalid.
        # If today == today it is NOT in the future, so it should pass.
        updated = service.update_demographics("DR-1", "P-001", {"date_of_birth": today})
        assert updated.date_of_birth == today

    def test_dob_one_day_in_future_raises_error(self, service):
        future = (datetime.utcnow() + timedelta(days=1)).strftime("%Y-%m-%d")
        with pytest.raises(InvalidDemographicsException, match="future"):
            service.update_demographics("DR-1", "P-001", {"date_of_birth": future})

    def test_dob_minimum_valid_date(self, service):
        """Oldest conceivable patient – year 1900."""
        updated = service.update_demographics(
            "DR-1", "P-001", {"date_of_birth": "1900-01-01"}
        )
        assert updated.date_of_birth == "1900-01-01"

    def test_dob_invalid_format_raises_error(self, service):
        for bad_dob in ["22-03-1985", "1985/03/22", "not-a-date", "", "19850322"]:
            with pytest.raises(InvalidDemographicsException, match="ISO-8601"):
                service.update_demographics(
                    "DR-1", "P-001", {"date_of_birth": bad_dob}
                )

    def test_dob_none_value_is_skipped(self, service):
        """Explicitly passing None for dob should not trigger date validation."""
        updated = service.update_demographics(
            "DR-1", "P-001", {"date_of_birth": None}
        )
        # The update is applied without error – None is stored.
        # (Adjust assertion to match your domain rules.)
        assert updated.date_of_birth is None

    def test_updated_at_is_utc_aware(self, service):
        updated = service.update_demographics("DR-1", "P-001", {"phone": "x"})
        assert updated.updated_at.tzinfo is not None

    def test_history_recorded_at_is_utc_aware(self, service, history_repo):
        service.update_demographics("DR-1", "P-001", {"phone": "x"})
        hist = history_repo.save.call_args[0][0]
        assert hist.recorded_at.tzinfo is not None

    def test_clock_leap_second_boundary(self, patient_repo, history_repo):
        """Simulate a timestamp at the leap-second boundary (23:59:60 approximated)."""
        leap_approx = datetime(2024, 12, 31, 23, 59, 59, 999999, tzinfo=timezone.utc)
        svc = PatientDemographicsService(
            patient_repo, history_repo, clock=lambda: leap_approx
        )
        updated = svc.update_demographics("DR-1", "P-001", {"phone": "x"})
        assert updated.updated_at == leap_approx

    def test_clock_midnight_boundary(self, patient_repo, history_repo):
        midnight = datetime(2024, 7, 1, 0, 0, 0, tzinfo=timezone.utc)
        svc = PatientDemographicsService(
            patient_repo, history_repo, clock=lambda: midnight
        )
        updated = svc.update_demographics("DR-1", "P-001", {"phone": "x"})
        assert updated.updated_at == midnight

    def test_dob_leap_day_valid(self, service):
        updated = service.update_demographics(
            "DR-1", "P-001", {"date_of_birth": "2000-02-29"}
        )
        assert updated.date_of_birth == "2000-02-29"

    def test_dob_feb_29_non_leap_year_raises(self, service):
        with pytest.raises(InvalidDemographicsException):
            service.update_demographics(
                "DR-1", "P-001", {"date_of_birth": "2001-02-29"}
            )


