class TestConcurrentVersionIntegrity:
    """
    Simulate sequential updates and verify that each version is numbered
    correctly and that every prior state is preserved.
    """

    def test_sequential_updates_increment_version_monotonically(
        self, patient_repo, history_repo, fixed_now
    ):
        # Use a real in-memory store instead of mocks for this integration-style test.
        store = {}
        history_store = []

        record = PatientDemographics(
            patient_id="P-999",
            first_name="Alice",
            last_name="Wonder",
            date_of_birth="1990-01-01",
            gender="female",
            phone="000-0000",
            address="Anywhere",
            weight_kg=55.0,
            height_cm=160.0,
            version=1,
        )
        store["P-999"] = record

        repo = MagicMock()
        repo.get.side_effect = lambda pid: store.get(pid)
        repo.save.side_effect = lambda p: store.update({p.patient_id: p})

        hist_repo = MagicMock()
        hist_repo.save.side_effect = lambda h: history_store.append(h)
        hist_repo.get_all.side_effect = lambda pid: [
            h for h in history_store if h.patient_id == pid
        ]

        svc = PatientDemographicsService(repo, hist_repo, clock=lambda: fixed_now)

        svc.update_demographics("DR-1", "P-999", {"phone": "111-1111"})
        svc.update_demographics("DR-1", "P-999", {"phone": "222-2222"})
        svc.update_demographics("DR-1", "P-999", {"address": "New Street 1"})

        assert store["P-999"].version == 4
        assert len(history_store) == 3
        versions = [h.version for h in history_store]
        assert versions == [1, 2, 3]

    def test_history_snapshots_contain_distinct_field_values(
        self, patient_repo, history_repo, fixed_now
    ):
