        repo = MagicMock()
        repo.get.side_effect = lambda pid: store.get(pid)
        repo.save.side_effect = lambda p: store.update({p.patient_id: p})

        hist_repo = MagicMock()
        hist_repo.save.side_effect = lambda h: history_store.append(h)

        svc = PatientDemographicsService(repo, hist_repo, clock=lambda: fixed_now)

        svc.update_demographics("DR-2", "P-888", {"phone": "111-1111"})
        svc.update_demographics("DR-2", "P-888", {"phone": "222-2222"})

        assert history_store[0].snapshot.phone == "000-0000"
        assert history_store[1].snapshot.phone == "111-1111"
        assert store["P-888"].phone == "222-2222"
